//DBAS SQLite Wrapper
class DbasSqliteWrapper {
    basePath = '/data/';
    dbName = '';
    dbPath = '';

    module = null;
    opfsDir = null;
    opfsHandles = new Map();
    opfsFs = null;

    async initialize(dbName = 'dbas.db') {
        this.closeOpfsHandles();
        this.module = await DbasSqlite();
        this.module._dbas_vfs_register();
        this.dbName = dbName.endsWith('.db') ? dbName : `${dbName}.db`;
        this.dbPath = dbName.endsWith('.db') ? `${this.basePath}${dbName}` : `${this.basePath}${dbName}.db`;

        try {
            if (!this.module.FS.lookupPath('/data').node) {
                this.module.FS.mkdir('/data');
            }
        } catch (e) {
            try {
                this.module.FS.mkdir('/data');
            } catch (e2) {
                // Directory likely already exists
            }
        }

        const root = await navigator.storage.getDirectory();
        this.opfsDir = await root.getDirectoryHandle('dbas_data', { create: true });

        this.opfsFs = this.createOpfsFs();
        this.module.FS.mount(this.opfsFs, {}, '/data');

        await this.openOpfsHandles();

        if (navigator.storage && navigator.storage.persist) {
            const alreadyPersisted = await navigator.storage.persisted();
            if (!alreadyPersisted) {
                const isPersisted = await navigator.storage.persist();
                if (!isPersisted) {
                    console.warn('⚠️ Failed to request persistent storage.');
                }
            }
        }
    }

    // ─── OPFS Backend ───

    async openOpfsHandles() {
        const rootNode = this.module.FS.lookupPath('/data').node;
        const extensions = ['', '-journal', '-wal', '-shm'];

        for (const ext of extensions) {
            const filename = this.dbName + ext;
            const fileHandle = await this.opfsDir.getFileHandle(filename, { create: true });
            const accessHandle = await fileHandle.createSyncAccessHandle();
            this.opfsHandles.set(filename, accessHandle);

            const node = this.opfsFs.createNode(rootNode, filename, 0o100666, 0);
            node.opfs_handle = accessHandle;
        }
    }

    closeOpfsHandles() {
        for (const handle of this.opfsHandles.values()) {
            try { handle.close(); } catch (_) {}
        }
        this.opfsHandles.clear();
    }

    createOpfsFs() {
        const wrapper = this;
        const FS = this.module.FS;

        const OPFSFS = {
            mount(mount) {
                const root = OPFSFS.createNode(null, '/', 0o40777, 0);
                root.mount = mount;
                return root;
            },

            createNode(parent, name, mode, dev) {
                const node = FS.createNode(parent, name, mode, dev);
                const isDir = FS.isDir(mode);

                if (isDir) {
                    node.node_ops = OPFSFS.dir_node_ops;
                    node.stream_ops = OPFSFS.dir_stream_ops;
                    node.contents = {};
                } else {
                    node.node_ops = OPFSFS.file_node_ops;
                    node.stream_ops = OPFSFS.file_stream_ops;
                    node.opfs_handle = null;
                }

                if (parent && parent.contents) {
                    parent.contents[name] = node;
                }

                return node;
            },

            dir_node_ops: {
                getattr(node) {
                    return {
                        dev: 1, ino: node.id, mode: node.mode, nlink: 1,
                        uid: 0, gid: 0, rdev: 0, size: 4096,
                        atime: new Date(), mtime: new Date(), ctime: new Date(),
                        blksize: 4096, blocks: 8
                    };
                },
                setattr(node, attr) {
                    if (attr.mode !== undefined) node.mode = attr.mode;
                },
                lookup(parent, name) {
                    if (!parent.contents || !parent.contents[name]) {
                        throw new FS.ErrnoError(44); // ENOENT
                    }
                    return parent.contents[name];
                },
                mknod(parent, name, mode, dev) {
                    const node = OPFSFS.createNode(parent, name, mode, dev);
                    const handle = wrapper.opfsHandles.get(name);
                    if (handle) {
                        node.opfs_handle = handle;
                        handle.truncate(0);
                    }
                    return node;
                },
                unlink(parent, name) {
                    const node = parent.contents[name];
                    if (node && node.opfs_handle) {
                        node.opfs_handle.truncate(0);
                    }
                    delete parent.contents[name];
                },
                readdir(node) {
                    return ['.', '..', ...Object.keys(node.contents || {})];
                },
                rename() { throw new FS.ErrnoError(63); },
                rmdir() { throw new FS.ErrnoError(63); }
            },

            file_node_ops: {
                getattr(node) {
                    let size = 0;
                    if (node.opfs_handle) {
                        try { size = node.opfs_handle.getSize(); } catch (_) {}
                    }
                    return {
                        dev: 1, ino: node.id, mode: node.mode, nlink: 1,
                        uid: 0, gid: 0, rdev: 0, size: size,
                        atime: new Date(), mtime: new Date(), ctime: new Date(),
                        blksize: 4096, blocks: Math.ceil(size / 4096) * 8
                    };
                },
                setattr(node, attr) {
                    if (attr.mode !== undefined) node.mode = attr.mode;
                    if (attr.size !== undefined && node.opfs_handle) {
                        node.opfs_handle.truncate(attr.size);
                    }
                }
            },

            file_stream_ops: {
                open(stream) {},
                close(stream) {},
                read(stream, buffer, offset, length, position) {
                    const handle = stream.node.opfs_handle;
                    if (!handle) return 0;
                    const view = new Uint8Array(buffer.buffer, buffer.byteOffset + offset, length);
                    return handle.read(view, { at: position });
                },
                write(stream, buffer, offset, length, position) {
                    const handle = stream.node.opfs_handle;
                    if (!handle) return 0;
                    const view = new Uint8Array(buffer.buffer, buffer.byteOffset + offset, length);
                    return handle.write(view, { at: position });
                },
                fsync(stream) {
                    const handle = stream.node.opfs_handle;
                    if (handle && handle.flush) handle.flush();
                    return 0;
                },
                llseek(stream, offset, whence) {
                    let position = offset;
                    if (whence === 1) {
                        position += stream.position;
                    } else if (whence === 2) {
                        if (stream.node.opfs_handle) {
                            position += stream.node.opfs_handle.getSize();
                        }
                    }
                    if (position < 0) throw new FS.ErrnoError(28);
                    return position;
                }
            },

            dir_stream_ops: {}
        };

        return OPFSFS;
    }

    // ─── Database Operations ───

    isFsAvailable() {
        return !!this.module && this.module.FS;
    }

    fileExists(path) {
        try {
            this.module.FS.stat(path);
            return true;
        } catch (e) {
            return false;
        }
    }

    databaseExists() {
        const handle = this.opfsHandles.get(this.dbName);
        return !!handle && handle.getSize() > 0;
    }

    attachDb(content) {
        try {
            this.module.FS.writeFile(this.dbPath, content);
        } catch (e) {
            try { this.module.FS.unlink(this.dbPath); } catch (_) {}
            throw e;
        }
    }

    async attachStreamDb(streamContent) {
        const reader = streamContent.getReader();
        const fd = this.module.FS.open(this.dbPath, 'w+');
        let offset = 0;

        try {
            while (true) {
                const { done, value } = await reader.read();
                if (done) break;
                const chunk = value instanceof Uint8Array ? value : new Uint8Array(value);
                this.module.FS.write(fd, chunk, 0, chunk.length, offset);
                offset += chunk.length;
            }
        } catch (e) {
            this.module.FS.close(fd);
            try { this.module.FS.unlink(this.dbPath); } catch (_) {}
            throw e;
        }

        this.module.FS.close(fd);
    }

    exportStreamDb(chunkSize = 65536) {
        const handle = this.opfsHandles.get(this.dbName);
        if (!handle) throw new Error('No database handle found');
        const fileSize = handle.getSize();
        let offset = 0;

        return new ReadableStream({
            pull(controller) {
                if (offset >= fileSize) {
                    controller.close();
                    return;
                }
                const remaining = fileSize - offset;
                const len = Math.min(chunkSize, remaining);
                const chunk = new Uint8Array(len);
                handle.read(chunk, { at: offset });
                offset += len;
                controller.enqueue(chunk);
            }
        });
    }

    async streamCopyDb(destName, chunkSize = 65536) {
        const srcHandle = this.opfsHandles.get(this.dbName);
        if (!srcHandle) throw new Error('No source database handle found');

        const destDbName = destName.endsWith('.db') ? destName : `${destName}.db`;
        const destFileHandle = await this.opfsDir.getFileHandle(destDbName, { create: true });
        const destAccessHandle = await destFileHandle.createSyncAccessHandle();

        try {
            destAccessHandle.truncate(0);
            const srcSize = srcHandle.getSize();
            let offset = 0;
            const chunk = new Uint8Array(chunkSize);

            while (offset < srcSize) {
                const remaining = srcSize - offset;
                const len = Math.min(chunkSize, remaining);
                const view = new Uint8Array(chunk.buffer, 0, len);
                srcHandle.read(view, { at: offset });
                destAccessHandle.write(view, { at: offset });
                offset += len;
            }

            destAccessHandle.flush();
        } finally {
            destAccessHandle.close();
        }

        return { destName: destDbName, size: srcHandle.getSize() };
    }

    async dropDb() {
        this.closeOpfsHandles();
        const extensions = ['', '-journal', '-wal', '-shm'];
        for (const ext of extensions) {
            const filename = this.dbName + ext;
            try { await this.opfsDir.removeEntry(filename); } catch (_) {}
        }
    }

    integrityCheck(dbPtr) {
        const rc = this.prepareQuery(dbPtr, 'PRAGMA integrity_check');
        if (rc !== 0) return { ok: false, error: this.getLastDbError(dbPtr) };

        const results = [];
        while (this.readRow(dbPtr) === 100) {
            results.push(this.getColumnText(dbPtr, 0));
        }
        this.closeReader(dbPtr);

        const ok = results.length === 1 && results[0] === 'ok';
        return { ok, results };
    }

    // ─── Connection Pool ───

    createPool(size = 4) {
        const dbPathPtr = this.allocString(this.dbPath);
        const poolPtr = this.module._CreatePool(dbPathPtr, size);
        this.module._free(dbPathPtr);
        if (!poolPtr) throw new Error('Failed to create connection pool');

        const wrapper = this;
        const writer = this.module._PoolGetWriter(poolPtr);

        return {
            poolPtr,
            writer,

            acquireReader() {
                const reader = wrapper.module._PoolAcquireReader(poolPtr);
                if (!reader) throw new Error('No available reader connections');
                return reader;
            },

            releaseReader(dbPtr) {
                wrapper.module._PoolReleaseReader(poolPtr, dbPtr);
            },

            exec(sql, params) {
                return executeOnConnection(wrapper, this.writer, sql, params);
            },

            query(sql, params) {
                const reader = this.acquireReader();
                try {
                    return queryOnConnection(wrapper, reader, sql, params);
                } finally {
                    this.releaseReader(reader);
                }
            },

            batch(statements) {
                for (const stmt of statements) {
                    executeOnConnection(wrapper, this.writer, stmt.sql, stmt.params);
                }
            },

            close() {
                wrapper.module._ClosePool(poolPtr);
            }
        };
    }

    // ─── SQLite C API Wrappers ───

    allocString(str) {
        const len = this.module.lengthBytesUTF8(str) + 1;
        const ptr = this.module._malloc(len);
        this.module.stringToUTF8(str, ptr, len);
        return ptr;
    }

    openDb() {
        const dbPathPtr = this.allocString(this.dbPath);
        const dbPtr = this.module._OpenDb(dbPathPtr);
        if (!dbPtr) {
            throw new Error(`Failed to open database with invalid pointer: ${this.dbPath}`);
        }
        this.module._free(dbPathPtr);
        return dbPtr;
    }

    isOpened(dbPtr) {
        return this.module._IsOpened(dbPtr);
    }

    executeSql(dbPtr, sql) {
        const sqlPtr = this.allocString(sql);
        try {
            return this.module._ExecuteSql(dbPtr, sqlPtr);
        } finally {
            this.module._free(sqlPtr);
        }
    }

    prepareQuery(dbPtr, sql) {
        const sqlPtr = this.allocString(sql);
        try {
            return this.module._PrepareQuery(dbPtr, sqlPtr);
        } finally {
            this.module._free(sqlPtr);
        }
    }

    bindText(dbPtr, index, value) {
        const textPtr = this.allocString(value);
        try {
            this.module._BindText(dbPtr, index, textPtr);
        } finally {
            this.module._free(textPtr);
        }
    }

    bindInt(dbPtr, index, value) {
        this.module._BindInt(dbPtr, index, value);
    }

    bindFloat(dbPtr, index, value) {
        this.module._BindFloat(dbPtr, index, value);
    }

    bindDouble(dbPtr, index, value) {
        this.module._BindDouble(dbPtr, index, value);
    }

    bindNull(dbPtr, index) {
        this.module._BindNull(dbPtr, index);
    }

    bindBlob(dbPtr, index, data) {
        const len = data?.length ?? 0;
        const dataPtr = this.module._malloc(len);
        try {
            this.module.HEAPU8.set(data, dataPtr);
            this.module._BindBlob(dbPtr, index, dataPtr, len);
        } finally {
            this.module._free(dataPtr);
        }
    }

    bindNameText(dbPtr, name, value) {
        const namePtr = this.allocString(name);
        const valuePtr = this.allocString(value);
        try {
            this.module._BindNameText(dbPtr, namePtr, valuePtr);
        } finally {
            this.module._free(namePtr);
            this.module._free(valuePtr);
        }
    }

    bindNameInt(dbPtr, name, value) {
        const namePtr = this.allocString(name);
        try {
            this.module._BindNameInt(dbPtr, namePtr, value);
        } finally {
            this.module._free(namePtr);
        }
    }

    bindNameFloat(dbPtr, name, value) {
        const namePtr = this.allocString(name);
        try {
            this.module._BindNameFloat(dbPtr, namePtr, value);
        } finally {
            this.module._free(namePtr);
        }
    }

    bindNameDouble(dbPtr, name, value) {
        const namePtr = this.allocString(name);
        try {
            this.module._BindNameDouble(dbPtr, namePtr, value);
        } finally {
            this.module._free(namePtr);
        }
    }

    bindNameNull(dbPtr, name) {
        const namePtr = this.allocString(name);
        try {
            this.module._BindNameNull(dbPtr, namePtr);
        } finally {
            this.module._free(namePtr);
        }
    }

    bindNameBlob(dbPtr, name, data) {
        const len = data?.length ?? 0;
        const namePtr = this.allocString(name);
        const dataPtr = this.module._malloc(len);
        try {
            this.module.HEAPU8.set(data, dataPtr);
            this.module._BindNameBlob(dbPtr, namePtr, dataPtr, len);
        } finally {
            this.module._free(namePtr);
            this.module._free(dataPtr);
        }
    }

    readRow(dbPtr) {
        return this.module._ReadRow(dbPtr);
    }

    isNull(dbPtr, index) {
        return this.module._IsNull(dbPtr, index);
    }

    getColumnText(dbPtr, index) {
        const textPtr = this.module._GetColumnText(dbPtr, index);
        return textPtr ? this.module.UTF8ToString(textPtr) : null;
    }

    getColumnInt(dbPtr, index) {
        return this.module._GetColumnInt(dbPtr, index);
    }

    getColumnFloat(dbPtr, index) {
        return this.module._GetColumnFloat(dbPtr, index);
    }

    getColumnDouble(dbPtr, index) {
        return this.module._GetColumnDouble(dbPtr, index);
    }

    getColumnType(dbPtr, index) {
        return this.module._GetColumnType(dbPtr, index);
    }

    getColumnBlob(dbPtr, index) {
        const blobPtr = this.module._GetColumnBlob(dbPtr, index);
        const length = this.module._GetColumnBytes(dbPtr, index);
        if (!blobPtr || length === 0) return null;
        const copy = new Uint8Array(length);
        copy.set(new Uint8Array(this.module.HEAPU8.buffer, blobPtr, length));
        return copy;
    }

    getColumnBytes(dbPtr, index) {
        return this.module._GetColumnBytes(dbPtr, index);
    }

    getColumnName(dbPtr, index) {
        const namePtr = this.module._GetColumnName(dbPtr, index);
        return namePtr ? this.module.UTF8ToString(namePtr) : null;
    }

    getColumnCount(dbPtr) {
        return this.module._GetColumnCount(dbPtr);
    }

    getLastDbError(dbPtr) {
        const errorPtr = this.module._GetLastDbError(dbPtr);
        return errorPtr ? this.module.UTF8ToString(errorPtr) : `Unknown error: ${errorPtr}`;
    }

    getAffectedRows(dbPtr) {
        return this.module._GetAffectedRows(dbPtr);
    }

    getLastInsertedId(dbPtr) {
        return this.module._GetLastInsertedId(dbPtr);
    }

    closeReader(dbPtr) {
        this.module._CloseReader(dbPtr);
    }

    closeDb(dbPtr) {
        this.module._CloseDb(dbPtr);
    }
}

function executeOnConnection(wrapper, dbPtr, sql, params) {
    if (params && Array.isArray(params) && params.length > 0) {
        if (wrapper.prepareQuery(dbPtr, sql) !== 0) throw new Error(wrapper.getLastDbError(dbPtr));
        for (let i = 0; i < params.length; i++) {
            const v = params[i], idx = i + 1;
            if (v === null || v === undefined) wrapper.bindNull(dbPtr, idx);
            else if (typeof v === 'number')
                Number.isInteger(v) ? wrapper.bindInt(dbPtr, idx, v) : wrapper.bindDouble(dbPtr, idx, v);
            else wrapper.bindText(dbPtr, idx, String(v));
        }
        const rc = wrapper.readRow(dbPtr);
        if (rc !== 100 && rc !== 101) throw new Error(wrapper.getLastDbError(dbPtr));
    } else if (params && !Array.isArray(params) && Object.keys(params).length > 0) {
        if (wrapper.prepareQuery(dbPtr, sql) !== 0) throw new Error(wrapper.getLastDbError(dbPtr));
        for (const [name, v] of Object.entries(params)) {
            if (v === null || v === undefined) wrapper.bindNameNull(dbPtr, name);
            else if (typeof v === 'number')
                Number.isInteger(v) ? wrapper.bindNameInt(dbPtr, name, v) : wrapper.bindNameDouble(dbPtr, name, v);
            else wrapper.bindNameText(dbPtr, name, String(v));
        }
        const rc = wrapper.readRow(dbPtr);
        if (rc !== 100 && rc !== 101) throw new Error(wrapper.getLastDbError(dbPtr));
    } else {
        const rc = wrapper.executeSql(dbPtr, sql);
        if (rc !== 0) throw new Error(wrapper.getLastDbError(dbPtr));
    }
}

function queryOnConnection(wrapper, dbPtr, sql, params) {
    if (wrapper.prepareQuery(dbPtr, sql) !== 0) throw new Error(wrapper.getLastDbError(dbPtr));
    if (params && Array.isArray(params) && params.length > 0) {
        for (let i = 0; i < params.length; i++) {
            const v = params[i], idx = i + 1;
            if (v === null || v === undefined) wrapper.bindNull(dbPtr, idx);
            else if (typeof v === 'number')
                Number.isInteger(v) ? wrapper.bindInt(dbPtr, idx, v) : wrapper.bindDouble(dbPtr, idx, v);
            else wrapper.bindText(dbPtr, idx, String(v));
        }
    } else if (params && !Array.isArray(params) && Object.keys(params).length > 0) {
        for (const [name, v] of Object.entries(params)) {
            if (v === null || v === undefined) wrapper.bindNameNull(dbPtr, name);
            else if (typeof v === 'number')
                Number.isInteger(v) ? wrapper.bindNameInt(dbPtr, name, v) : wrapper.bindNameDouble(dbPtr, name, v);
            else wrapper.bindNameText(dbPtr, name, String(v));
        }
    }
    const rows = [];
    while (wrapper.readRow(dbPtr) === 100) {
        const colCount = wrapper.getColumnCount(dbPtr);
        const row = {};
        for (let i = 0; i < colCount; i++) {
            const name = wrapper.getColumnName(dbPtr, i);
            const type = wrapper.getColumnType(dbPtr, i);
            if (type === 1) row[name] = wrapper.getColumnInt(dbPtr, i);
            else if (type === 2) row[name] = wrapper.getColumnDouble(dbPtr, i);
            else if (type === 4) row[name] = wrapper.getColumnBlob(dbPtr, i);
            else if (type === 5) row[name] = null;
            else row[name] = wrapper.getColumnText(dbPtr, i);
        }
        rows.push(row);
    }
    wrapper.closeReader(dbPtr);
    return rows;
}
//End of DBAS SQLite Wrapper

// Export for global access (better for Dart JS interop)
if (typeof DbasSqlite !== 'undefined') {
  globalThis.DbasSqlite = DbasSqlite;
} else {
  console.error('❌ DbasSqlite is not defined');
}

if (typeof DbasSqliteWrapper !== 'undefined') {
  globalThis.DbasSqliteWrapper = new DbasSqliteWrapper();
} else {
  console.error('❌ DbasSqliteWrapper is not defined');
}

globalThis.initPersistentFS = async function(dbName = 'dbas.db') {
  const module = globalThis.DbasSqliteWrapper;
  await module.initialize(dbName);
  return module;
}

globalThis.dropDb = () => globalThis.DbasSqliteWrapper.dropDb();
globalThis.isFsAvailable = () => globalThis.DbasSqliteWrapper.isFsAvailable();
